188	    // apply: reconciliation-먼저 순서로 WORKSTATE에 전이를 적용한다. rollback + FATAL 분류 포함.
189	    private static int RunApply(string[] args)
190	    {
191	        var opts = ParseApplyArgs(args);
192	        if (opts is null)
193	        {
194	            Console.Error.WriteLine("{\"error\":\"apply에는 --envelope 이 필요합니다\"}");
195	            return 2;
196	        }
197	
198	        // Envelope 읽기 — 이 단계는 atomic write 전이므로 예외 발생 시 rollback 불필요.
199	        var envelope = ReadEnvelope(opts.EnvelopePath);
200	        if (envelope is null) return 2;
201	
202	        // unknown transitionKind는 fail-closed — NORMAL/PHASE_CHANGE/RECOVERY/REPLAY 외 거부.
203	        if (!ValidTransitionKinds.Contains(envelope.TransitionKind))
204	            return Fail(1, envelope.TransitionId, "unknown-transition-kind",
205	                $"transitionKind='{envelope.TransitionKind}'은 알 수 없는 종류입니다 (허용: NORMAL, PHASE_CHANGE, RECOVERY, REPLAY)");
206	
207	        // high-risk transitionKind — receipt ledger 부재로 항상 fail-closed.
208	        if (HighRiskKinds.Contains(envelope.TransitionKind))
209	            return Fail(1, envelope.TransitionId, "trusted-human-receipt-required",
210	                $"transitionKind={envelope.TransitionKind}는 receipt ledger 부재로 이번 WP에서 fail-closed");
211	
212	        var ctx = LoadWorkstateContext();
213	        if (ctx is null) return 2;
214	        var (root, workstatePath, logPath, rawWorkstateBytes, workstate, rawWorkstateStr) = ctx.Value;
215	
216	        // Step 1: request sha256 + candidate file hash 검증.
217	        var (_, request, evidenceExit) = VerifyApplyEvidence(envelope);
218	        if (evidenceExit.HasValue) return evidenceExit.Value;
219	
220	        // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.
221	        // ★ 순서 정정(§1): reconciliation이 existing-transition보다 먼저여야 가짜 id 공격을 막는다.
222	        ReconciliationResult reconResult;
223	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath)); }
224	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return 2; }
225	
226	        if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
227	        {
228	            var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
229	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply", $"reconciliation failed: {codes}");
230	        }
231	
232	        // Step 3: existing-transition 판정 (idempotent / collision / legacy-unverifiable).
233	        // ★ 순서 정정(§1): existing-transition이 pre-state hash보다 먼저여야 재시도가 산다.
234	        var existingResult = CheckExistingTransition(workstate, reconResult, envelope);
235	        if (existingResult.HasValue) return existingResult.Value;
236	
237	        // Steps 4-6: candidate 재계산 + 검증 + dry-run.
238	        var (recompCandidate, recompBytes, validateExit) =
239	            RunApplyValidatePhase(envelope, workstate, rawWorkstateStr, request!, opts.DryRun, root);
240	        if (validateExit.HasValue) return validateExit.Value;
241	
242	        // Steps 7-10: atomic write + post-apply 검사 + v2 log.
243	        return RunApplyCommitPhase(
244	            envelope, workstatePath, logPath,
245	            rawWorkstateBytes, workstate, recompCandidate!, recompBytes!);
246	    }
