248	    // 저장소 루트를 찾고 WORKSTATE를 로드한다. 실패 시 null 반환(오류는 stderr에 기록).
249	    private static (string root, string workstatePath, string logPath, byte[] rawBytes, JsonObject workstate, string rawStr)?
250	        LoadWorkstateContext()
251	    {
252	        try
253	        {
254	            var root = GitTools.FindRepoRoot();
