267	    // request sha256 + candidate file hash를 검증한다. 성공 시 (rawRequest, request, null) 반환.
268	    private static (string? rawRequest, JsonObject? request, int? exitCode) VerifyApplyEvidence(EnvelopeData envelope)
269	    {
270	        if (!File.Exists(envelope.RequestPath)) { WriteError($"request file not found: {envelope.RequestPath}"); return (null, null, 2); }
271	        string rawRequest;
272	        JsonObject request;
273	        try
274	        {
275	            rawRequest = File.ReadAllText(envelope.RequestPath, new UTF8Encoding(false));
276	            var actualRequestSha = ComputeSha256(rawRequest);
277	            if (!string.Equals(actualRequestSha, envelope.RequestSha256, StringComparison.OrdinalIgnoreCase))
278	                return (null, null, Fail(1, envelope.TransitionId, "request-sha256-mismatch",
279	                    "request file changed since prepare"));
280	            request = JsonNode.Parse(rawRequest)?.AsObject()
281	                ?? throw new InvalidOperationException("request JSON must be a JSON object");
282	        }
283	        catch (Exception ex) { WriteError(ex.Message); return (null, null, 2); }
284	
285	        if (!File.Exists(envelope.CandidatePath)) { WriteError($"candidate file not found: {envelope.CandidatePath}"); return (null, null, 2); }
286	        try
287	        {
288	            var candidateFileHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(envelope.CandidatePath))).ToLowerInvariant();
289	            if (!string.Equals(candidateFileHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
290	                return (null, null, Fail(1, envelope.TransitionId, "candidate-tampered",
291	                    "candidate file hash differs from envelope.expectedPostStateSha256 — evidence may have been tampered"));
292	        }
293	        catch (Exception ex) { WriteError($"candidate 파일 읽기 실패: {ex.Message}"); return (null, null, 2); }
294	
295	        return (rawRequest, request, null);
296	    }
