298	    // Steps 4-6: candidate 재계산 + hash 검증 + pre-state hash + request 검증 + dry-run 처리.
299	    private static (JsonObject? candidate, byte[]? bytes, int? earlyExit) RunApplyValidatePhase(
300	        EnvelopeData envelope, JsonObject workstate, string rawWorkstateStr,
301	        JsonObject request, bool dryRun, string root)
302	    {
303	        JsonObject recomputedCandidate;
304	        byte[] recomputedBytes;
305	        try
306	        {
307	            // Step 4: 메모리에서 candidate 재계산 + hash 검증 (TOCTOU 방어).
308	            recomputedCandidate = BuildCandidate(workstate, request, envelope.TransitionId, envelope.EffectiveAt);
309	            recomputedBytes = Encoding.UTF8.GetBytes(recomputedCandidate.ToJsonString(WriteOptions));
310	            var recomputedHash = Convert.ToHexString(SHA256.HashData(recomputedBytes)).ToLowerInvariant();
311	            if (!string.Equals(recomputedHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
312	                return (null, null, Fail(1, envelope.TransitionId, "candidate-recompute-mismatch",
313	                    "recomputed candidate hash differs — WORKSTATE or request changed since prepare"));
314	        }
315	        catch (Exception ex) { WriteError($"candidate 재계산 실패: {ex.Message}"); return (null, null, 2); }
316	
317	        // Step 5: pre-state hash 검증 (미적용 ID에 한해 실행).
318	        var currentHash = ComputeSha256(rawWorkstateStr);
319	        if (!string.Equals(currentHash, envelope.ExpectedPreStateSha256, StringComparison.OrdinalIgnoreCase))
320	            return (null, null, Fail(1, envelope.TransitionId, "pre-state-hash-mismatch",
321	                $"expected={Short(envelope.ExpectedPreStateSha256)} actual={Short(currentHash)}"));
322	
323	        // Step 6: request 검증.
324	        var validErr = ValidateRequestForApply(request, envelope, workstate, root);
325	        if (validErr is not null)
326	            return (null, null, Fail(1, envelope.TransitionId, "validation-failed", validErr));
327	
328	        if (dryRun)
329	        {
330	            Console.WriteLine(new JsonObject
331	            {
332	                ["ok"] = true, ["dryRun"] = true,
333	                ["transitionId"] = envelope.TransitionId,
334	                ["previousStatus"] = workstate["status"]?.ToString(),
335	                ["newStatus"] = recomputedCandidate["status"]?.ToString(),
336	            }.ToJsonString(WriteOptions));
337	            return (null, null, 0);
338	        }
339	
340	        return (recomputedCandidate, recomputedBytes, null);
341	    }
