343	    // Steps 7-10: preimage 저장 → atomic write → test seam → post-apply 검사 → v2 log append.
344	    private static int RunApplyCommitPhase(
345	        EnvelopeData envelope, string workstatePath, string logPath,
346	        byte[] rawWorkstateBytes, JsonObject workstate, JsonObject recomputedCandidate, byte[] recomputedBytes)
347	    {
348	        // Step 7: preimage 저장 — atomic replace 전에 반드시 저장해야 한다.
349	        var preimage = rawWorkstateBytes;
350	        var preimageHash = Convert.ToHexString(SHA256.HashData(preimage)).ToLowerInvariant();
351	
352	        // Step 8: atomic replace — 재계산 bytes만 사용(candidate 파일은 evidence, write source 아님).
353	        try { var t = workstatePath + ".stateapplier.tmp"; File.WriteAllBytes(t, recomputedBytes); File.Move(t, workstatePath, overwrite: true); }
354	        catch (Exception ex) { WriteError($"atomic write 실패: {ex.Message}"); return 2; }
355	
356	        // 결정적 test seam — in-process 훅만 허용. 환경변수는 읽지 않는다.
357	        var seamFail = FailAfterWriteHook?.Invoke();
358	        if (seamFail is not null)
359	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, seamFail);
360	
361	        // Step 9: 적용후 검사 — 항상 projection 실행.
362	        var projExit = ProjectionCli.Run(["projection"]);
363	        if (projExit != 0)
364	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, "projection-failed");
365	
366	        // 내부 checker — PendingTransitionId로 pending 면제 경로를 실증한다.
367	        ReconciliationResult reconAfter;
368	        try { reconAfter = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath, envelope.TransitionId)); }
369	        catch (Exception ex)
370	        {
371	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
372	                $"post-apply checker 실행 실패: {ex.Message}");
373	        }
374	
375	        if (reconAfter.Failures.Count > 0 || reconAfter.HarnessErrors.Count > 0)
376	        {
377	            var codes = string.Join("; ", reconAfter.Failures.Concat(reconAfter.HarnessErrors).Select(f => f.Code));
378	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
379	                $"post-apply-integrity-failed: {codes}");
380	        }
381	
382	        // Step 10: v2 log append — 성공 경로에서만.
383	        string newSha;
384	        try { newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false))); }
385	        catch (Exception ex) { WriteError($"적용 후 hash 계산 실패: {ex.Message}"); return 2; }
386	
387	        var logContractHash = ComputeContractHash(
388	            envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
389	            envelope.ExpectedPreStateSha256, newSha, envelope.EffectiveAt);
390	        try
391	        {
392	            AppendApplierLogV2(logPath, envelope.TransitionId, "ok", 0, envelope.TransitionKind,
393	                envelope.RequestSha256, envelope.ExpectedPreStateSha256, newSha, logContractHash, envelope.EffectiveAt);
394	        }
395	        catch (Exception logEx)
396	        {
397	            Console.Error.WriteLine(new JsonObject
398	            {
399	                ["fatal"] = "AUDIT_LOG_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
400	                ["detail"] = $"v2 log append threw: {logEx.Message} — 다음 전이 금지, log 수동 검증 필요",
401	            }.ToJsonString());
402	            return 2;
403	        }
404	
405	        Console.WriteLine(new JsonObject
406	        {
407	            ["ok"] = true, ["transitionId"] = envelope.TransitionId,
408	            ["previousStatus"] = workstate["status"]?.ToString(),
409	            ["newStatus"] = recomputedCandidate["status"]?.ToString(),
410	            ["workstateSha256"] = newSha,
411	            ["pendingExemptionUsed"] = reconAfter.Metrics?.PendingExemptionApplied,
412	        }.ToJsonString(WriteOptions));
413	        return 0;
414	    }
