416	    // rollback: preimage를 복원하고 FATAL taxonomy에 따라 exit code와 로그를 결정한다.
417	    private static int Rollback(
418	        string workstatePath, string logPath, byte[] preimage, string preimageHash,
419	        EnvelopeData envelope, string failureReason)
420	    {
421	        try
422	        {
423	            File.WriteAllBytes(workstatePath, preimage);
424	            var restoredStr = File.ReadAllText(workstatePath, new UTF8Encoding(false));
425	            var restoredHash = ComputeSha256(restoredStr);
426	
427	            if (!string.Equals(restoredHash, preimageHash, StringComparison.OrdinalIgnoreCase))
428	            {
429	                // 복원 후 hash 불일치 — FATAL.
430	                AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
431	                Console.Error.WriteLine(new JsonObject
432	                {
433	                    ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
434	                    ["detail"] = "preimage 복원 hash 불일치 — 모든 자동작업 중단. HUMAN-INBOX 필요.",
435	                }.ToJsonString());
436	                return 2;
437	            }
438	
439	            // rollback 후 항상 projection 재생성 시도.
440	            var projExit = ProjectionCli.Run(["projection"]);
441	            if (projExit != 0)
442	            {
443	                AppendLogSafe(logPath, envelope.TransitionId, "STATE_RESTORED_PROJECTION_NOT_VERIFIED", 2);
444	                Console.Error.WriteLine(new JsonObject
445	                {
446	                    ["fatal"] = "STATE_RESTORED_PROJECTION_NOT_VERIFIED",
447	                    ["transitionId"] = envelope.TransitionId,
448	                    ["detail"] = "WORKSTATE 복원 성공, projection 재생성 실패 — HUMAN-INBOX 필요.",
449	                }.ToJsonString());
450	                return 2;
451	            }
452	
453	            AppendLogSafe(logPath, envelope.TransitionId, "ROLLED_BACK", 1);
454	            Console.Error.WriteLine(new JsonObject
455	            {
456	                ["ok"] = false, ["result"] = "ROLLED_BACK",
457	                ["transitionId"] = envelope.TransitionId,
458	                ["failureReason"] = failureReason,
459	                ["restoredHash"] = restoredHash,
460	                ["detail"] = "WORKSTATE 복원 완료. 전이 효과 없음.",
461	            }.ToJsonString());
462	            return 1;
463	        }
464	        catch (Exception ex)
465	        {
466	            // 복원 자체 실패 — FATAL.
467	            AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
468	            Console.Error.WriteLine(new JsonObject
469	            {
470	                ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
471	                ["detail"] = $"preimage 복원 실패: {ex.Message} — 모든 자동작업 중단.",
472	            }.ToJsonString());
473	            return 2;
474	        }
475	    }
