563	    // effectiveAt을 외부에서 받아 결정적 candidate를 구성한다. UtcNow 호출 없음.
564	    private static JsonObject BuildCandidate(
565	        JsonObject current, JsonObject request, string transitionId, string effectiveAt)
566	    {
567	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
568	
569	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
570	        {
571	            if (request[key] is JsonNode node)
572	                candidate[key] = node.DeepClone();
573	        }
574	
575	        // updatedAt은 effectiveAt의 날짜 부분으로 결정한다 — UtcNow 호출 없음.
576	        if (DateTimeOffset.TryParse(effectiveAt, null, DateTimeStyles.RoundtripKind, out var ea))
577	            candidate["updatedAt"] = ea.ToString("yyyy-MM-dd");
578	
579	        if (candidate["appliedTransitions"] is not JsonArray applied)
580	        {
581	            applied = new JsonArray();
582	            candidate["appliedTransitions"] = applied;
583	        }
584	
585	        applied.Add(new JsonObject
586	        {
587	            ["id"] = transitionId,
588	            ["appliedAt"] = effectiveAt,
589	        });
590	
591	        return candidate;
592	    }
593	
594	    // apply 경로용 request 검증 — human-decision 플래그 없이 동작한다.
595	    private static string? ValidateRequestForApply(
596	        JsonObject request, EnvelopeData envelope, JsonObject current, string root)
597	    {
598	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
599	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
600	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
601	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
602	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
603	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
604	
605	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
606	        if (!ValidStatuses.Contains(newStatus))
607	            return $"status '{newStatus}'는 허용 목록에 없습니다";
608	
609	        var currentStatus = current["status"]?.ToString() ?? "";
610	        var currentDiId = current["diId"]?.ToString() ?? "";
611	        var requestDiId = request["diId"]?.ToString();
612	
613	        var transErr = ValidateStatusTransition(currentStatus, newStatus, currentDiId, requestDiId);
614	        if (transErr is not null) return transErr;
615	
616	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
617	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
618	
619	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
620	            return "status=blocked인데 blockers가 비어있습니다";
621	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
622	            return $"status={newStatus}인데 nextActions가 비어있습니다";
623	
624	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
625	        {
626	            var targetDiId = requestDiId ?? currentDiId;
627	            var wsUpdatedAt = current["updatedAt"]?.ToString() ?? "";
628	            var verdictErr = ValidateVerdict(null, targetDiId, wsUpdatedAt);
629	            if (verdictErr is not null) return verdictErr;
630	        }
631	
632	        var curPhase = current["phaseId"]?.ToString();
633	        var newPhase = request["phaseId"]?.ToString();
634	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
635	            return $"Phase 전이({curPhase} → {newPhase})는 transitionKind=PHASE_CHANGE를 사용하세요 (이번 WP fail-closed)";
636	
637	        if (!string.IsNullOrWhiteSpace(root))
638	        {
639	            var wpId = request["wpId"]?.ToString() ?? current["wpId"]?.ToString();
640	            if (!string.IsNullOrWhiteSpace(wpId))
641	            {
642	                var regErr = ValidateWpRegistry(root, wpId);
643	                if (regErr is not null) return regErr;
644	            }
645	        }
646	        return null;
647	    }
648	
649	    // DI 경계와 전이 그래프를 검사한다.
650	    private static string? ValidateStatusTransition(
651	        string currentStatus, string newStatus, string currentDiId, string? requestDiId)
652	    {
653	        var isNewDi = requestDiId is not null &&
654	                      !string.Equals(requestDiId, currentDiId, StringComparison.OrdinalIgnoreCase);
655	
656	        if (isNewDi)
657	        {
658	            if (!string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
659	                return $"새 DI 착수({currentDiId} → {requestDiId})는 현재 DI가 completed여야 합니다(현재: {currentStatus})";
660	            if (!string.Equals(newStatus, "waiting", StringComparison.OrdinalIgnoreCase) &&
661	                !string.Equals(newStatus, "in_progress", StringComparison.OrdinalIgnoreCase))
662	                return $"새 DI 착수 시 status는 waiting 또는 in_progress만 허용합니다(요청: {newStatus})";
663	            return null;
664	        }
665	
666	        if (string.Equals(currentStatus, newStatus, StringComparison.OrdinalIgnoreCase)) return null;
667	
668	        // completed는 terminal.
669	        if (string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
670	            return $"completed 상태 전이({currentStatus} → {newStatus})는 허용되지 않습니다 — completed는 terminal 상태입니다";
671	
672	        if (AllowedTransitions.TryGetValue(currentStatus, out var allowed) && !allowed.Contains(newStatus))
673	        {
674	            var allowedStr = allowed.Count > 0 ? string.Join(", ", allowed) : "없음(terminal)";
675	            return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
676	        }
677	        return null;
678	    }
679	
680	    // gate.json 형식·gateVerdict·failureCount·taskId 일치·stale 여부를 검증한다.
681	    private static string? ValidateVerdict(string? verdictPath, string targetDiId, string workstateUpdatedAt)
682	    {
683	        if (string.IsNullOrWhiteSpace(verdictPath))
684	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
685	
686	        var normalized = verdictPath.Replace('\\', '/');
687	        var fileName = Path.GetFileName(normalized);
688	        if (!fileName.EndsWith(".gate.json", StringComparison.OrdinalIgnoreCase))
689	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
690	
691	        var dirPart = Path.GetDirectoryName(normalized)?.Replace('\\', '/') ?? "";
692	        if (!dirPart.EndsWith("outputs/gates", StringComparison.OrdinalIgnoreCase))
693	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
694	
695	        if (!File.Exists(verdictPath)) return $"verdict file not found: {verdictPath}";
696	
697	        var gateJson = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
698	        if (gateJson is null) return "gate JSON이 유효하지 않습니다";
699	
700	        var gateVerdict = gateJson["gateVerdict"]?.ToString();
701	        if (!string.Equals(gateVerdict, "PASS", StringComparison.OrdinalIgnoreCase))
702	            return $"gate verdict가 PASS가 아닙니다(gateVerdict={gateVerdict ?? "null"})";
703	
704	        var failureCount = gateJson["failureCount"]?.GetValue<int>() ?? -1;
705	        if (failureCount != 0) return $"gate failureCount가 0이 아닙니다(failureCount={failureCount})";
706	
707	        var gateTaskId = gateJson["taskId"]?.ToString();
708	        if (!string.Equals(gateTaskId, targetDiId, StringComparison.OrdinalIgnoreCase))
709	            return $"gate taskId({gateTaskId ?? "null"})가 전이 대상 DI({targetDiId})와 일치하지 않습니다";
710	
711	        var createdAtStr = gateJson["createdAt"]?.ToString();
712	        if (createdAtStr is not null &&
713	            DateTimeOffset.TryParse(createdAtStr, out var createdAt) &&
714	            DateTime.TryParse(workstateUpdatedAt, out var wsUpdated) &&
715	            createdAt.Date < wsUpdated.Date)
716	        {
717	            return $"gate 증거가 WORKSTATE updatedAt({workstateUpdatedAt})보다 오래됐습니다(gate createdAt={createdAt:yyyy-MM-dd})";
718	        }
719	        return null;
720	    }
721	
722	    // wpId가 WP-REGISTRY.json에 등록되어 있는지 검사한다.
723	    private static string? ValidateWpRegistry(string root, string wpId)
724	    {
725	        var registryPath = Path.Combine(root, "docs", "handoff", "WP-REGISTRY.json");
726	        if (!File.Exists(registryPath)) return "WP-REGISTRY.json not found — WP 등록표가 없습니다";
727	        var reg = JsonNode.Parse(File.ReadAllText(registryPath))?.AsObject();
728	        if (reg is null) return "WP-REGISTRY.json이 유효한 JSON 객체가 아닙니다";
729	        var wps = reg["wps"] as JsonArray;
730	        if (wps is null) return "WP-REGISTRY.json에 'wps' 배열이 없습니다";
731	        var exists = wps.OfType<JsonObject>().Any(w =>
732	            string.Equals(w["wpId"]?.ToString(), wpId, StringComparison.OrdinalIgnoreCase));
733	        return exists ? null : $"wpId '{wpId}'가 WP-REGISTRY.json에 등록되지 않았습니다 — WP 추가는 사람 결재입니다";
734	    }
735	
736	    // 고정 순서 JSON 직렬화로 계약 hash를 계산한다.
737	    private static string ComputeContractHash(
738	        string transitionId, string transitionKind, string requestSha256,
739	        string preStateSha256, string postStateSha256, string effectiveAt)
740	    {
741	        var sb = new StringBuilder();
742	        sb.Append("{\"effectiveAt\":\"").Append(effectiveAt).Append('"');
743	        sb.Append(",\"postStateSha256\":\"").Append(postStateSha256).Append('"');
744	        sb.Append(",\"preStateSha256\":\"").Append(preStateSha256).Append('"');
745	        sb.Append(",\"requestSha256\":\"").Append(requestSha256).Append('"');
746	        sb.Append(",\"transitionId\":\"").Append(transitionId).Append('"');
747	        sb.Append(",\"transitionKind\":\"").Append(transitionKind).Append("\"}");
748	        return ComputeSha256(sb.ToString());
749	    }
750	
751	    // v2 format으로 applier-log에 항목을 추가한다.
752	    private static void AppendApplierLogV2(
753	        string logPath, string transitionId, string result, int exitCode,
754	        string transitionKind, string requestSha256, string preStateSha256,
755	        string postStateSha256, string contractSha256, string effectiveAt)
756	    {
757	        var entry = new JsonObject
758	        {
759	            ["transitionId"] = transitionId,
760	            ["result"] = result,
761	            ["exitCode"] = exitCode,
762	            ["at"] = DateTime.UtcNow.ToString("o"),
763	            ["schemaVersion"] = 2,
