774	    // rollback/error 이벤트를 applier-log에 한 줄 추가한다.
775	    private static void AppendApplierLog(string logPath, string transitionId, string result, int exitCode)
776	    {
777	        var entry = new JsonObject
778	        {
779	            ["transitionId"] = transitionId,
780	            ["result"] = result,
781	            ["exitCode"] = exitCode,
782	            ["at"] = DateTime.UtcNow.ToString("o"),
783	        };
784	        File.AppendAllText(logPath, entry.ToJsonString() + "\n", new UTF8Encoding(false));
