786	
787	    // 예외를 삼키고 log append를 시도한다 — rollback 경로의 best-effort 로깅.
788	    private static void AppendLogSafe(string logPath, string transitionId, string result, int exitCode)
789	    {
790	        try { AppendApplierLog(logPath, transitionId, result, exitCode); } catch { }
