793	    // 이미 적용된 transition-id에 대한 idempotent 응답을 출력하고 0을 반환한다.
794	    private static int ReportIdempotent(string transitionId)
795	    {
796	        Console.WriteLine(new JsonObject
797	        {
798	            ["ok"] = true,
799	            ["transitionId"] = transitionId,
800	            ["idempotent"] = true,
801	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
802	        }.ToJsonString(WriteOptions));
803	        return 0;
804	    }
