806	    // prepare 인수를 파싱한다.
807	    private static PrepareOptions? ParsePrepareArgs(string[] args)
808	    {
809	        var map = ParseFlagMap(args, 2);
810	        var dryRun = map.ContainsKey("dry-run-flag"); map.Remove("dry-run-flag");
811	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
812	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
813	        return new PrepareOptions(tid, req, dryRun);
814	    }
815	
816	    // apply 인수를 파싱한다.
817	    private static ApplyOptions? ParseApplyArgs(string[] args)
818	    {
819	        var map = ParseFlagMap(args, 2);
820	        var dryRun = map.ContainsKey("dry-run-flag"); map.Remove("dry-run-flag");
821	        if (!map.TryGetValue("envelope", out var env) || string.IsNullOrWhiteSpace(env)) return null;
822	        map.TryGetValue("verdict", out var verdict);
823	        return new ApplyOptions(env, verdict, dryRun);
824	    }
825	
826	    // args[startIndex]부터 --key value 쌍을 파싱한다. --dry-run은 "dry-run-flag"="1"로 저장.
827	    private static Dictionary<string, string> ParseFlagMap(string[] args, int startIndex)
828	    {
829	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
830	        for (var i = startIndex; i < args.Length; i++)
831	        {
832	            if (string.Equals(args[i], "--dry-run", StringComparison.OrdinalIgnoreCase))
833	            {
834	                map["dry-run-flag"] = "1";
835	                continue;
836	            }
837	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
838	            {
839	                map[args[i][2..]] = args[i + 1];
840	                i++;
841	            }
842	        }
843	        return map;
844	    }
845	
846	    // 문자열의 SHA-256을 소문자 hex로 반환한다.
847	    private static string ComputeSha256(string content)
848	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
849	
850	    // stderr에 JSON 오류 메시지를 출력한다.
851	    private static void WriteError(string message)
852	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
853	
854	    // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
855	    private static int Fail(int exitCode, string transitionId, string reason, string detail)
856	    {
857	        Console.Error.WriteLine(new JsonObject
858	        {
859	            ["ok"] = false,
860	            ["transitionId"] = transitionId,
861	            ["reason"] = reason,
862	            ["detail"] = detail,
863	        }.ToJsonString());
864	        return exitCode;
865	    }
866	
867	    // sha256 문자열의 앞 16자 + "..."를 반환한다.
868	    private static string Short(string s) => s.Length > 16 ? s[..16] + "..." : s;
869	}
