            if (!ok) mismatches.Add(new JsonObject { ["case"] = "fatal-restore-failed", ["expected"] = "exit=2,FATAL_STATE_UNKNOWN", ["actual"] = $"exit={applyExit},fatal={fatalLogged}" });
